document['addEventListener']('DOMContentLoaded',function(){const Y=document['querySelectorAll']('.date-control');Y['forEach']((q,k)=>{q['addEventListener']('keydown',function(Q){if('Tab'===Q['key']){if(Q['preventDefault'](),Q['shiftKey']){const p=Y[k-0x1];p&&p['focus']();}else{const a=Y[k+0x1];a&&a['focus']();}}});});});